	description "Sample Iproute container";
        list iproute {
            key "name";
            description "List of interfaces in the system";
            leaf name {
                type string;
		pattern '(([0-9]{1,2})\/([0-9]{1,2}))';
		description "slot/port argument of the interface";
            }
            leaf ip{
                type string;
		description "IP address subnet";
            }
            leaf prefix{
                type string;
		description "prefix length";
            }
            leaf gateway{
                type string;
		description "gateway";
            }
